package api

import (
	"encoding/json"
	"net/http"
	"time"

	"gpfs.local/daycount/internal/daycount"
)

type request struct {
	Start     string  `json:"start"`     // YYYY-MM-DD
	End       string  `json:"end"`       // YYYY-MM-DD
	Basis     string  `json:"basis"`     // ACT/360, ACT/365, 30/360
	Principal float64 `json:"principal"` // notional, accrued endpoint only
	Rate      float64 `json:"rate"`      // annual coupon as a decimal
}

func decode(w http.ResponseWriter, r *http.Request) (time.Time, time.Time, request, bool) {
	var req request
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "invalid JSON body", http.StatusBadRequest)
		return time.Time{}, time.Time{}, req, false
	}
	start, err1 := time.Parse("2006-01-02", req.Start)
	end, err2 := time.Parse("2006-01-02", req.End)
	if err1 != nil || err2 != nil || !end.After(start) {
		http.Error(w, "start/end must be valid dates with end after start", http.StatusBadRequest)
		return time.Time{}, time.Time{}, req, false
	}
	return start, end, req, true
}

// DayCountHandler returns the day-count fraction for the supplied basis.
func DayCountHandler(w http.ResponseWriter, r *http.Request) {
	start, end, req, ok := decode(w, r)
	if !ok {
		return
	}
	days, frac, err := daycount.Fraction(start, end, req.Basis)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	writeJSON(w, map[string]any{"days": days, "fraction": frac, "basis": req.Basis})
}

// AccruedHandler returns accrued interest = principal * rate * day-count fraction.
func AccruedHandler(w http.ResponseWriter, r *http.Request) {
	start, end, req, ok := decode(w, r)
	if !ok {
		return
	}
	_, frac, err := daycount.Fraction(start, end, req.Basis)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	accrued := req.Principal * req.Rate * frac
	writeJSON(w, map[string]any{"accrued": accrued, "fraction": frac, "basis": req.Basis})
}

func writeJSON(w http.ResponseWriter, v any) {
	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(v)
}

// Package daycount implements common fixed-income day-count conventions.
// All functions are pure: deterministic arithmetic on the supplied dates.
package daycount

import (
	"fmt"
	"time"
)

// Fraction returns the elapsed day count and the year fraction for a basis.
func Fraction(start, end time.Time, basis string) (int, float64, error) {
	switch basis {
	case "ACT/360":
		d := actualDays(start, end)
		return d, float64(d) / 360.0, nil
	case "ACT/365":
		d := actualDays(start, end)
		return d, float64(d) / 365.0, nil
	case "30/360":
		d := thirty360Days(start, end)
		return d, float64(d) / 360.0, nil
	default:
		return 0, 0, fmt.Errorf("unsupported basis %q (use ACT/360, ACT/365, or 30/360)", basis)
	}
}

func actualDays(start, end time.Time) int {
	return int(end.Sub(start).Hours() / 24)
}

// thirty360Days applies the US (NASD) 30/360 adjustment.
func thirty360Days(start, end time.Time) int {
	d1, m1, y1 := start.Day(), int(start.Month()), start.Year()
	d2, m2, y2 := end.Day(), int(end.Month()), end.Year()
	if d1 == 31 {
		d1 = 30
	}
	if d2 == 31 && d1 == 30 {
		d2 = 30
	}
	return (y2-y1)*360 + (m2-m1)*30 + (d2 - d1)
}

