/*
  Procedure : dbo.PostCapitalCall
  Purpose   : Posts a capital call drawdown for a single investor.
              Writes the funding event to the capital account ledger and
              updates the investor's running balance (system of record).
  Author    : Fund Accounting / GP Fund Solutions
  Notes     : Run as part of the capital call close. Amount is the called
              (drawn) amount in fund base currency.
*/
SET ANSI_NULLS ON;
SET QUOTED_IDENTIFIER ON;
GO

CREATE PROCEDURE dbo.PostCapitalCall
    @InvestorId   INT,
    @CallId       INT,
    @Amount       DECIMAL(19, 2),
    @PostingDate  DATE = NULL
AS
BEGIN
    SET NOCOUNT ON;

    -- default posting date to today if not supplied
    IF @PostingDate IS NULL
        SET @PostingDate = CAST(SYSUTCDATETIME() AS DATE);

    BEGIN TRY
        BEGIN TRANSACTION;

        -- 1) record the drawdown line in the ledger of record
        INSERT INTO dbo.CapitalAccountLedger
            (InvestorId, CallId, EntryType, Amount, PostingDate, CreatedAtUtc)
        VALUES
            (@InvestorId, @CallId, 'CAPITAL_CALL', @Amount, @PostingDate, SYSUTCDATETIME());

        -- 2) roll the called amount into the investor's running balance
        UPDATE dbo.InvestorBalances
        SET Balance      = Balance + @Amount,
            LastUpdated  = SYSUTCDATETIME()
        WHERE InvestorId = @InvestorId;

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0
            ROLLBACK TRANSACTION;
        THROW;  -- bubble the error up to the caller
    END CATCH;
END;
GO

